def _ensure_package(name: str):
    module = sys.modules.get(name)
    if module is None:
        module = types.ModuleType(name)
        module.__package__ = name
        module.__path__ = []
        module.__file__ = f'<{name}>'
        sys.modules[name] = module
    parent_name, _, child_name = name.rpartition('.')
    if parent_name:
        parent = _ensure_package(parent_name)
        setattr(parent, child_name, module)
    return module

def _ensure_module(name: str):
    module = sys.modules.get(name)
    if module is None:
        parent_name, _, child_name = name.rpartition('.')
        if parent_name:
            parent = _ensure_package(parent_name)
        else:
            parent = None
        module = types.ModuleType(name)
        module.__package__ = parent_name
        module.__file__ = f'<{name}>'
        sys.modules[name] = module
        if parent is not None:
            setattr(parent, child_name, module)
    return module

def _runtime_is_complete():
    root = sys.modules.get(_RUNTIME_PACKAGE)
    if root is None or not getattr(root, '__embedded_bootstrap_loaded__', False):
        return False
    for module_name in _RUNTIME_ORDER:
        if _RUNTIME_SOURCES.get(module_name, '') and module_name not in sys.modules:
            return False
    return True

def _bootstrap_runtime():
    if _runtime_is_complete():
        return sys.modules[_RUNTIME_PACKAGE]
    for package_name in _PACKAGE_NAMES:
        _ensure_package(package_name)
    for module_name in _RUNTIME_ORDER:
        source = _RUNTIME_SOURCES.get(module_name, '')
        module = _ensure_package(module_name) if module_name in _PACKAGE_NAMES else _ensure_module(module_name)
        if source and not module.__dict__.get('__embedded_bootstrap_loaded__', False):
            module.__dict__.setdefault('__builtins__', __builtins__)
            exec(source, module.__dict__)
            module.__dict__['__embedded_bootstrap_loaded__'] = True
    sys.modules[_RUNTIME_PACKAGE].__embedded_bootstrap_loaded__ = True
    return sys.modules[_RUNTIME_PACKAGE]

def _require_runtime_module(name: str):
    _bootstrap_runtime()
    module = sys.modules.get(name)
    if module is not None:
        return module
    source = _RUNTIME_SOURCES.get(name, '')
    if source:
        module = _ensure_package(name) if name in _PACKAGE_NAMES else _ensure_module(name)
        if not module.__dict__.get('__embedded_bootstrap_loaded__', False):
            module.__dict__.setdefault('__builtins__', __builtins__)
            exec(source, module.__dict__)
            module.__dict__['__embedded_bootstrap_loaded__'] = True
        sys.modules[_RUNTIME_PACKAGE].__embedded_bootstrap_loaded__ = True
        return module
    raise RuntimeError(f'Embedded runtime module is missing: {name}')

_bootstrap_runtime()

import sys
from pathlib import Path
from typing import Any, Dict, Tuple

__runtime_module_1 = _require_runtime_module('manufacturing_langflow_runtime.component_base')
Component = __runtime_module_1.Component
DataInput = __runtime_module_1.DataInput
Output = __runtime_module_1.Output
make_branch_data = __runtime_module_1.make_branch_data
read_state_payload = __runtime_module_1.read_state_payload
__runtime_module_2 = _require_runtime_module('manufacturing_langflow_runtime._runtime.graph.builder')
route_after_resolve = __runtime_module_2.route_after_resolve


class RouteModeComponent(Component):
    display_name = "Route Mode"
    description = "Expose the first query-mode branch as visible Langflow output ports."
    documentation = "https://docs.langflow.org/components-custom-components"
    icon = "GitFork"
    name = "route_mode"

    inputs = [DataInput(name="state", display_name="State", info="State with query_mode already decided")]
    outputs = [
        Output(name="followup_out", display_name="Followup", method="followup_state", group_outputs=True, types=["Data"], selected="Data"),
        Output(name="retrieval_out", display_name="Retrieval", method="retrieval_state", group_outputs=True, types=["Data"], selected="Data"),
    ]

    _cached: Tuple[Dict[str, Any], str] | None = None

    def _resolve(self) -> Tuple[Dict[str, Any], str]:
        if self._cached is not None:
            return self._cached
        state = read_state_payload(getattr(self, "state", None))
        route = route_after_resolve(state) if state else ""
        self.status = f"Query route: {route or 'inactive'}"
        self._cached = (state, route)
        return self._cached

    def followup_state(self):
        state, route = self._resolve()
        return make_branch_data(route == "followup_analysis", {"state": state})

    def retrieval_state(self):
        state, route = self._resolve()
        return make_branch_data(route == "plan_retrieval", {"state": state})
